export const componentSources = {
  "holographic-card": "\"use client\";\n\nimport { useRef } from \"react\";\nimport { motion, useMotionValue, useSpring, useTransform } from \"framer-motion\";\nimport { cn } from \"@/lib/utils\";\n\nexport function HolographicCard({\n    children,\n    className,\n}: {\n    children: React.ReactNode;\n    className?: string;\n}) {\n    const ref = useRef<HTMLDivElement>(null);\n\n    const x = useMotionValue(0);\n    const y = useMotionValue(0);\n\n    const mouseXSpring = useSpring(x, { stiffness: 200, damping: 25 });\n    const mouseYSpring = useSpring(y, { stiffness: 200, damping: 25 });\n\n    const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], [\"12deg\", \"-12deg\"]);\n    const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], [\"-12deg\", \"12deg\"]);\n\n    // The specular highlight follows cursor position exactly\n    const highlightX = useTransform(mouseXSpring, [-0.5, 0.5], [\"0%\", \"100%\"]);\n    const highlightY = useTransform(mouseYSpring, [-0.5, 0.5], [\"0%\", \"100%\"]);\n    const highlightOpacity = useTransform(\n        mouseXSpring,\n        [-0.5, -0.1, 0, 0.1, 0.5],\n        [0.15, 0.4, 0.5, 0.4, 0.15]\n    );\n\n    const reflectionOpacity = useTransform(mouseYSpring, [-0.5, 0, 0.5], [0.6, 0.2, 0]);\n\n    const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {\n        if (!ref.current) return;\n        const rect = ref.current.getBoundingClientRect();\n        x.set((e.clientX - rect.left) / rect.width - 0.5);\n        y.set((e.clientY - rect.top) / rect.height - 0.5);\n    };\n\n    const handleMouseLeave = () => {\n        x.set(0);\n        y.set(0);\n    };\n\n    return (\n        <motion.div\n            ref={ref}\n            onMouseMove={handleMouseMove}\n            onMouseLeave={handleMouseLeave}\n            style={{\n                rotateX,\n                rotateY,\n                transformStyle: \"preserve-3d\",\n                perspective: \"1000px\",\n            }}\n            className={cn(\n                \"relative rounded-xl bg-[#0a0a0a] border border-white/[0.08]\",\n                \"cursor-default group/card\",\n                className\n            )}\n        >\n            {/* Specular light — a tight, bright elliptical highlight that moves with the cursor */}\n            <motion.div\n                className=\"pointer-events-none absolute inset-0 z-10 rounded-xl overflow-hidden\"\n                style={{ transform: \"translateZ(5px)\" }}\n            >\n                <motion.div\n                    className=\"absolute w-[200%] h-[200%]\"\n                    style={{\n                        left: highlightX,\n                        top: highlightY,\n                        x: \"-50%\",\n                        y: \"-50%\",\n                        opacity: highlightOpacity,\n                        background:\n                            \"radial-gradient(ellipse 35% 35% at 50% 50%, rgba(255,255,255,0.35) 0%, rgba(255,255,255,0.08) 40%, transparent 70%)\",\n                    }}\n                />\n            </motion.div>\n\n            {/* Reflection line — a single bright edge that simulates a light source above */}\n            <motion.div\n                className=\"pointer-events-none absolute inset-x-0 top-0 z-10 h-px rounded-t-xl\"\n                style={{\n                    opacity: reflectionOpacity,\n                    background: \"linear-gradient(90deg, transparent, rgba(255,255,255,0.5), transparent)\",\n                }}\n            />\n\n            {/* Content — pushed forward in Z-space for real depth */}\n            <div\n                className=\"relative z-20 h-full w-full\"\n                style={{ transform: \"translateZ(25px)\" }}\n            >\n                {children}\n            </div>\n        </motion.div>\n    );\n}\n",
  "kinetic-button": "\"use client\";\r\n\r\nimport { useRef, useState, useCallback } from \"react\";\r\nimport { motion } from \"framer-motion\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ninterface KineticButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {\r\n    children: React.ReactNode;\r\n    className?: string;\r\n    magneticPull?: number;\r\n    variant?: \"primary\" | \"secondary\" | \"ghost\" | \"danger\";\r\n}\r\n\r\nexport function KineticButton({\r\n    children,\r\n    className,\r\n    magneticPull = 0.2,\r\n    variant = \"primary\",\r\n    ...props\r\n}: KineticButtonProps) {\r\n    const ref = useRef<HTMLButtonElement>(null);\r\n    const [position, setPosition] = useState({ x: 0, y: 0 });\r\n    const [glowPos, setGlowPos] = useState({ x: 0, y: 0 });\r\n    const [isHovered, setIsHovered] = useState(false);\r\n\r\n    const handleMouse = useCallback((e: React.MouseEvent<HTMLButtonElement>) => {\r\n        if (!ref.current) return;\r\n        const { clientX, clientY } = e;\r\n        const { height, width, left, top } = ref.current.getBoundingClientRect();\r\n\r\n        // Magnetic displacement\r\n        const middleX = clientX - (left + width / 2);\r\n        const middleY = clientY - (top + height / 2);\r\n        setPosition({ x: middleX * magneticPull, y: middleY * magneticPull });\r\n\r\n        // Internal glow position (percentage-based for the shimmer)\r\n        setGlowPos({ x: ((clientX - left) / width) * 100, y: ((clientY - top) / height) * 100 });\r\n    }, [magneticPull]);\r\n\r\n    const reset = useCallback(() => {\r\n        setPosition({ x: 0, y: 0 });\r\n        setIsHovered(false);\r\n    }, []);\r\n\r\n    const variants = {\r\n        primary: \"bg-white text-black shadow-[0_0_20px_rgba(255,255,255,0.1)] hover:shadow-[0_0_25px_rgba(255,255,255,0.2)]\",\r\n        secondary: \"bg-[#111] text-white border border-white/10 hover:border-white/20 shadow-[0_0_15px_rgba(0,0,0,0.5)]\",\r\n        ghost: \"bg-transparent text-white/70 hover:text-white border border-transparent hover:border-white/[0.05] hover:bg-white/[0.02]\",\r\n        danger: \"bg-red-500/10 text-red-500 border border-red-500/20 hover:bg-red-500/20 hover:border-red-500/30\",\r\n    };\r\n\r\n    const glowColors = {\r\n        primary: \"rgba(0,0,0,0.1)\",\r\n        secondary: \"rgba(255,255,255,0.15)\",\r\n        ghost: \"rgba(255,255,255,0.08)\",\r\n        danger: \"rgba(239,68,68,0.2)\", // red-500\r\n    };\r\n\r\n    const borderTrackingColors = {\r\n        primary: \"rgba(0,0,0,0)\",\r\n        secondary: \"rgba(255,255,255,0.4)\",\r\n        ghost: \"rgba(255,255,255,0.2)\",\r\n        danger: \"rgba(239,68,68,0.5)\",\r\n    };\r\n\r\n    return (\r\n        <motion.button\r\n            ref={ref}\r\n            onMouseMove={handleMouse as (e: React.MouseEvent<Element, MouseEvent>) => void}\r\n            onMouseEnter={() => setIsHovered(true)}\r\n            onMouseLeave={reset}\r\n            animate={{ x: position.x, y: position.y }}\r\n            whileTap={{ scale: 0.95 }}\r\n            transition={{ type: \"spring\", stiffness: 200, damping: 15, mass: 0.1 }}\r\n            className={cn(\r\n                \"relative inline-flex items-center justify-center px-6 py-3 rounded-full font-semibold text-[13px] tracking-wide overflow-hidden\",\r\n                \"transition-colors duration-300 focus:outline-none cursor-pointer group\",\r\n                variants[variant],\r\n                className\r\n            )}\r\n            {...(props as React.ComponentPropsWithoutRef<typeof motion.button>)}\r\n        >\r\n            {/* Ambient Border Tracker (Only visible on hover, mask hides the center) */}\r\n            {variant !== \"primary\" && (\r\n                <div\r\n                    className=\"absolute inset-0 rounded-full transition-opacity duration-300 pointer-events-none opacity-0 group-hover:opacity-100\"\r\n                    style={{\r\n                        background: `radial-gradient(circle 50px at ${glowPos.x}% ${glowPos.y}%, ${borderTrackingColors[variant]}, transparent 100%)`,\r\n                        padding: \"1px\", // Acts as a border width\r\n                        WebkitMask: \"linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0)\",\r\n                        WebkitMaskComposite: \"xor\",\r\n                        maskComposite: \"exclude\",\r\n                    }}\r\n                />\r\n            )}\r\n\r\n            {/* Internal Shimmer Layer */}\r\n            <div\r\n                className=\"pointer-events-none absolute inset-0 rounded-full transition-opacity duration-300\"\r\n                style={{\r\n                    opacity: isHovered ? 1 : 0,\r\n                    background: `radial-gradient(circle 60px at ${glowPos.x}% ${glowPos.y}%, ${glowColors[variant]}, transparent 70%)`,\r\n                }}\r\n            />\r\n\r\n            <span className=\"relative z-10 inline-flex items-center gap-2 whitespace-nowrap transition-transform duration-200 group-active:scale-[0.98]\">\r\n                {children}\r\n            </span>\r\n        </motion.button>\r\n    );\r\n}\r\n",
  "grid-system": "\"use client\";\n\nimport { useRef, useState, useCallback, useMemo } from \"react\";\nimport { motion, useSpring, useMotionValue, useMotionTemplate } from \"framer-motion\";\nimport { cn } from \"@/lib/utils\";\n\ninterface GridSystemProps extends React.HTMLAttributes<HTMLDivElement> {\n    type?: \"dot\" | \"line\" | \"cross\";\n    size?: number;\n    color?: string; // Base dim grid color\n    interactiveColor?: string; // Reveal highlight color\n    animated?: boolean;\n    interactive?: boolean;\n    fadeMask?: \"radial\" | \"linear\" | \"none\";\n    className?: string;\n}\n\nexport function GridSystem({\n    type = \"dot\",\n    size = 40,\n    color = \"rgba(255,255,255,0.05)\",\n    interactiveColor = \"rgba(255,255,255,0.8)\",\n    animated = false,\n    interactive = true,\n    fadeMask = \"radial\",\n    className,\n    ...props\n}: GridSystemProps) {\n    const divRef = useRef<HTMLDivElement>(null);\n    const [isHovered, setIsHovered] = useState(false);\n\n    const safeColor = color.replace(/[<>\"'&]/g, \"\");\n    const safeInteractiveColor = interactiveColor.replace(/[<>\"'&]/g, \"\");\n\n    // Dynamic SVG Generation for absolute precision\n    const patternUrl = useMemo(() => {\n        let svg = \"\";\n        const c = size / 2;\n\n        if (type === \"dot\") {\n            svg = `<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"${size}\" height=\"${size}\"><circle cx=\"${c}\" cy=\"${c}\" r=\"1\" fill=\"${safeColor}\"/></svg>`;\n        } else if (type === \"line\") {\n            svg = `<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"${size}\" height=\"${size}\"><path d=\"M0 0h${size}M0 0v${size}\" stroke=\"${safeColor}\" stroke-width=\"1\" fill=\"none\"/></svg>`;\n        } else if (type === \"cross\") {\n            const l = 4; // arm length\n            svg = `<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"${size}\" height=\"${size}\"><path d=\"M${c} ${c - l}v${l * 2}M${c - l} ${c}h${l * 2}\" stroke=\"${safeColor}\" stroke-width=\"1\" fill=\"none\"/></svg>`;\n        }\n        return `url(\"data:image/svg+xml;utf8,${encodeURIComponent(svg)}\")`;\n    }, [type, size, safeColor]);\n\n    const highlightUrl = useMemo(() => {\n        let svg = \"\";\n        const c = size / 2;\n        if (type === \"dot\") {\n            svg = `<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"${size}\" height=\"${size}\"><circle cx=\"${c}\" cy=\"${c}\" r=\"1.5\" fill=\"${safeInteractiveColor}\"/></svg>`;\n        } else if (type === \"line\") {\n            svg = `<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"${size}\" height=\"${size}\"><path d=\"M0 0h${size}M0 0v${size}\" stroke=\"${safeInteractiveColor}\" stroke-width=\"1\" fill=\"none\"/></svg>`;\n        } else if (type === \"cross\") {\n            const l = 4;\n            svg = `<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"${size}\" height=\"${size}\"><path d=\"M${c} ${c - l}v${l * 2}M${c - l} ${c}h${l * 2}\" stroke=\"${safeInteractiveColor}\" stroke-width=\"1.5\" fill=\"none\"/></svg>`;\n        }\n        return `url(\"data:image/svg+xml;utf8,${encodeURIComponent(svg)}\")`;\n    }, [type, size, safeInteractiveColor]);\n\n    const mouseX = useMotionValue(0);\n    const mouseY = useMotionValue(0);\n    const smoothX = useSpring(mouseX, { stiffness: 300, damping: 30, mass: 0.5 });\n    const smoothY = useSpring(mouseY, { stiffness: 300, damping: 30, mass: 0.5 });\n\n    const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {\n        if (!divRef.current || !interactive) return;\n        const rect = divRef.current.getBoundingClientRect();\n        mouseX.set(e.clientX - rect.left);\n        mouseY.set(e.clientY - rect.top);\n    }, [mouseX, mouseY, interactive]);\n\n    const spotlightMask = useMotionTemplate`radial-gradient(150px circle at ${smoothX}px ${smoothY}px, black, transparent 80%)`;\n\n    // Static layout masks\n    const getLayoutMask = () => {\n        if (fadeMask === \"radial\") {\n            return \"radial-gradient(ellipse at center, black 20%, transparent 80%)\";\n        } else if (fadeMask === \"linear\") {\n            return \"linear-gradient(to bottom, black 20%, transparent 100%)\";\n        }\n        return \"none\";\n    };\n\n    return (\n        <div\n            ref={divRef}\n            onMouseMove={handleMouseMove}\n            onMouseEnter={() => setIsHovered(true)}\n            onMouseLeave={() => setIsHovered(false)}\n            className={cn(\"relative w-full h-full overflow-hidden bg-[#0a0a0a]\", className)}\n            style={{ WebkitMaskImage: getLayoutMask() }}\n            {...props}\n        >\n            {/* Base Background Grid */}\n            <div\n                className={cn(\n                    \"absolute inset-0 z-0\",\n                    animated && \"animate-[grid-drift_60s_linear_infinite]\"\n                )}\n                style={{\n                    backgroundImage: patternUrl,\n                    backgroundSize: `${size}px ${size}px`,\n                    // Animate drift using CSS animation instead of Framer for 0 overhead on static views\n                    transform: animated ? \"translateX(-50%) translateY(-50%)\" : \"none\",\n                    width: animated ? \"200%\" : \"100%\",\n                    height: animated ? \"200%\" : \"100%\",\n                }}\n            />\n\n            {/* Interactive Spotlight Overlay */}\n            {interactive && (\n                <motion.div\n                    className=\"absolute inset-0 z-10 transition-opacity duration-500 pointer-events-none mix-blend-screen\"\n                    style={{\n                        opacity: isHovered ? 1 : 0,\n                        WebkitMaskImage: spotlightMask,\n                        maskImage: spotlightMask,\n                    }}\n                >\n                    <div\n                        className={cn(\n                            \"absolute inset-0\",\n                            animated && \"animate-[grid-drift_60s_linear_infinite]\"\n                        )}\n                        style={{\n                            backgroundImage: highlightUrl,\n                            backgroundSize: `${size}px ${size}px`,\n                            transform: animated ? \"translateX(-50%) translateY(-50%)\" : \"none\",\n                            width: animated ? \"200%\" : \"100%\",\n                            height: animated ? \"200%\" : \"100%\",\n                        }}\n                    />\n                </motion.div>\n            )}\n        </div>\n    );\n}\n",
  "radial-noise": "\"use client\";\r\n\r\nimport { useRef, useState, useCallback, useEffect } from \"react\";\r\nimport { motion, useSpring, useMotionValue, useMotionTemplate } from \"framer-motion\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ninterface RadialNoiseProps extends React.HTMLAttributes<HTMLDivElement> {\r\n    children?: React.ReactNode;\r\n    className?: string;\r\n    spotlightSize?: number;\r\n    baseColor?: string;\r\n    glowColor?: string;\r\n    noiseOpacity?: number;\r\n    interactive?: boolean;\r\n    frequency?: number;\r\n}\r\n\r\nexport function RadialNoise({\r\n    children,\r\n    className,\r\n    spotlightSize = 400,\r\n    baseColor = \"#050505\",\r\n    glowColor = \"rgba(168, 85, 247, 0.4)\", // Purple default\r\n    noiseOpacity = 0.5,\r\n    interactive = true,\r\n    frequency = 0.8,\r\n    ...props\r\n}: RadialNoiseProps) {\r\n    const divRef = useRef<HTMLDivElement>(null);\r\n    const [isHovered, setIsHovered] = useState(false);\r\n\r\n    const mouseX = useMotionValue(0);\r\n    const mouseY = useMotionValue(0);\r\n\r\n    const smoothX = useSpring(mouseX, { stiffness: 300, damping: 30, mass: 0.5 });\r\n    const smoothY = useSpring(mouseY, { stiffness: 300, damping: 30, mass: 0.5 });\r\n\r\n    const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {\r\n        if (!divRef.current || !interactive) return;\r\n        const rect = divRef.current.getBoundingClientRect();\r\n        mouseX.set(e.clientX - rect.left);\r\n        mouseY.set(e.clientY - rect.top);\r\n    }, [mouseX, mouseY, interactive]);\r\n\r\n    const handleMouseLeave = useCallback(() => {\r\n        setIsHovered(false);\r\n        if (!divRef.current || !interactive) return;\r\n        const rect = divRef.current.getBoundingClientRect();\r\n        // Return to center gracefully\r\n        mouseX.set(rect.width / 2);\r\n        mouseY.set(rect.height / 2);\r\n    }, [mouseX, mouseY, interactive]);\r\n\r\n    // Set initial position to center on mount\r\n    useEffect(() => {\r\n        if (divRef.current) {\r\n            const rect = divRef.current.getBoundingClientRect();\r\n            mouseX.set(rect.width / 2);\r\n            mouseY.set(rect.height / 2);\r\n        }\r\n    }, [mouseX, mouseY]);\r\n\r\n    const spotlight = useMotionTemplate`radial-gradient(${spotlightSize}px circle at ${smoothX}px ${smoothY}px, ${glowColor}, transparent 80%)`;\r\n\r\n    return (\r\n        <div\r\n            ref={divRef}\r\n            onMouseMove={handleMouseMove}\r\n            onMouseEnter={() => setIsHovered(true)}\r\n            onMouseLeave={handleMouseLeave}\r\n            className={cn(\"relative w-full h-full overflow-hidden\", className)}\r\n            style={{ backgroundColor: baseColor }}\r\n            {...props}\r\n        >\r\n            {/* SVG Fractal Noise Layer */}\r\n            <div\r\n                className=\"absolute inset-0 z-0 pointer-events-none mix-blend-overlay\"\r\n                style={{\r\n                    opacity: noiseOpacity,\r\n                    backgroundImage: `url(\"data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='${frequency}' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E\")`,\r\n                }}\r\n            />\r\n\r\n            {/* Color Dodge Interaction Light (ignites the noise texture) */}\r\n            {interactive && (\r\n                <motion.div\r\n                    className=\"absolute inset-0 z-10 pointer-events-none mix-blend-color-dodge transition-opacity duration-1000\"\r\n                    style={{\r\n                        background: spotlight,\r\n                        opacity: isHovered ? 1 : 0.4, // Keep a soft glow in center when idle\r\n                    }}\r\n                />\r\n            )}\r\n\r\n            {/* Ambient Base Light (fills space so the background isn't pure black) */}\r\n            {interactive && (\r\n                <motion.div\r\n                    className=\"absolute inset-0 z-0 pointer-events-none transition-opacity duration-1000\"\r\n                    style={{\r\n                        background: spotlight,\r\n                        opacity: isHovered ? 0.3 : 0.1,\r\n                    }}\r\n                />\r\n            )}\r\n\r\n            <div className=\"relative z-20 h-full w-full\">{children}</div>\r\n        </div>\r\n    );\r\n}\r\n",
  "spotlight-card": "\"use client\";\r\n\r\nimport { useRef, useState, useCallback } from \"react\";\r\nimport { motion, useSpring, useMotionValue, useMotionTemplate } from \"framer-motion\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ninterface SpotlightCardProps extends React.HTMLAttributes<HTMLDivElement> {\r\n    children: React.ReactNode;\r\n    className?: string;\r\n    spotlightColor?: string;\r\n    spotlightSize?: number;\r\n    withNoise?: boolean;\r\n}\r\n\r\nexport function SpotlightCard({\r\n    children,\r\n    className,\r\n    spotlightColor = \"rgba(255, 255, 255, 0.03)\",\r\n    spotlightSize = 400,\r\n    withNoise = true,\r\n    ...props\r\n}: SpotlightCardProps) {\r\n    const divRef = useRef<HTMLDivElement>(null);\r\n    const [opacity, setOpacity] = useState(0);\r\n\r\n    const mouseX = useMotionValue(0);\r\n    const mouseY = useMotionValue(0);\r\n\r\n    // Apply spring physics for buttery smooth light tracking rather than raw mouse jumps\r\n    const smoothX = useSpring(mouseX, { stiffness: 300, damping: 30, mass: 0.5 });\r\n    const smoothY = useSpring(mouseY, { stiffness: 300, damping: 30, mass: 0.5 });\r\n\r\n    const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {\r\n        if (!divRef.current) return;\r\n        const rect = divRef.current.getBoundingClientRect();\r\n        mouseX.set(e.clientX - rect.left);\r\n        mouseY.set(e.clientY - rect.top);\r\n    }, [mouseX, mouseY]);\r\n\r\n    // Motion templates for highly performant CSS updates\r\n    const borderBackground = useMotionTemplate`radial-gradient(${spotlightSize * 0.8}px circle at ${smoothX}px ${smoothY}px, rgba(255,255,255,0.4), transparent 50%)`;\r\n    const interiorBackground = useMotionTemplate`radial-gradient(${spotlightSize}px circle at ${smoothX}px ${smoothY}px, ${spotlightColor}, transparent 60%)`;\r\n    const noiseMask = useMotionTemplate`radial-gradient(${spotlightSize}px circle at ${smoothX}px ${smoothY}px, black, transparent 80%)`;\r\n\r\n    return (\r\n        <div\r\n            ref={divRef}\r\n            onMouseMove={handleMouseMove}\r\n            onMouseEnter={() => setOpacity(1)}\r\n            onMouseLeave={() => setOpacity(0)}\r\n            className={cn(\r\n                \"relative overflow-hidden rounded-[2rem] bg-[#050505] border border-white/[0.04] transition-colors duration-500\",\r\n                \"hover:border-white/[0.08] shadow-[0_0_40px_rgba(0,0,0,0.5)]\",\r\n                className\r\n            )}\r\n            {...props}\r\n        >\r\n            {/* Base ambient noise (very subtle background grain) */}\r\n            {withNoise && (\r\n                <div\r\n                    className=\"absolute inset-0 opacity-[0.02] pointer-events-none mix-blend-overlay z-0\"\r\n                    style={{\r\n                        backgroundImage: `url(\"data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E\")`,\r\n                    }}\r\n                />\r\n            )}\r\n\r\n            {/* Glowing border trace - CSS Masking over Framer Motion Template */}\r\n            <motion.div\r\n                className=\"pointer-events-none absolute -inset-px z-10 transition-opacity duration-500 rounded-[2rem]\"\r\n                style={{\r\n                    opacity: opacity,\r\n                    background: borderBackground,\r\n                    WebkitMaskImage: `linear-gradient(#000, #000) content-box, linear-gradient(#000, #000)`,\r\n                    WebkitMaskComposite: \"xor\",\r\n                    maskImage: `linear-gradient(#000, #000) content-box, linear-gradient(#000, #000)`,\r\n                    maskComposite: \"exclude\",\r\n                    padding: \"1px\",\r\n                }}\r\n            />\r\n\r\n            {/* Interior radiant glow */}\r\n            <motion.div\r\n                className=\"pointer-events-none absolute inset-0 z-0 transition-opacity duration-500\"\r\n                style={{\r\n                    opacity: opacity,\r\n                    background: interiorBackground,\r\n                }}\r\n            />\r\n\r\n            {/* Illuminated Noise Overlay - only visible exactly where the light shines */}\r\n            {withNoise && (\r\n                <motion.div\r\n                    className=\"absolute inset-0 z-10 pointer-events-none mix-blend-color-dodge transition-opacity duration-500\"\r\n                    style={{\r\n                        opacity: opacity * 0.8,\r\n                        WebkitMaskImage: noiseMask,\r\n                        backgroundImage: `url(\"data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E\")`,\r\n                    }}\r\n                />\r\n            )}\r\n\r\n            <div className=\"relative z-20 h-full w-full\">{children}</div>\r\n        </div>\r\n    );\r\n}\r\n",
  "blur-text": "\"use client\";\n\nimport { useEffect, useRef } from \"react\";\nimport { motion, useInView, useAnimation, Variants } from \"framer-motion\";\nimport { cn } from \"@/lib/utils\";\n\ninterface BlurTextProps {\n    children: string;\n    className?: string;\n    delay?: number;\n    stagger?: number;\n    duration?: number;\n    splitBy?: \"chars\" | \"words\";\n    once?: boolean;\n}\n\nexport function BlurText({\n    children,\n    className,\n    delay = 0,\n    stagger = 0.05,\n    duration = 0.8,\n    splitBy = \"chars\",\n    once = false,\n}: BlurTextProps) {\n    const ref = useRef<HTMLDivElement>(null);\n    const inView = useInView(ref, { once });\n    const controls = useAnimation();\n\n    useEffect(() => {\n        if (inView) {\n            controls.start(\"visible\");\n        } else if (!once) {\n            controls.start(\"hidden\");\n        }\n    }, [inView, controls, once]);\n\n    const containerVariants: Variants = {\n        hidden: { opacity: 0 },\n        visible: {\n            opacity: 1,\n            transition: {\n                staggerChildren: stagger,\n                delayChildren: delay,\n            },\n        },\n    };\n\n    const itemVariants: Variants = {\n        hidden: {\n            opacity: 0,\n            y: 20,\n            filter: \"blur(15px)\",\n        },\n        visible: {\n            opacity: 1,\n            y: 0,\n            filter: \"blur(0px)\",\n            transition: {\n                duration: duration,\n                ease: \"easeOut\",\n            },\n        },\n    };\n\n    const words = children.split(\" \");\n    const elements: React.ReactNode[] = [];\n\n    words.forEach((word, wordIndex) => {\n        if (splitBy === \"words\") {\n            elements.push(\n                <motion.span\n                    key={wordIndex}\n                    variants={itemVariants}\n                    className=\"inline-block\"\n                >\n                    {word}\n                </motion.span>\n            );\n            if (wordIndex < words.length - 1) {\n                elements.push(<span key={\"space-\" + wordIndex}>&nbsp;</span>);\n            }\n        } else {\n            // Chars\n            const chars = word.split(\"\");\n            const charElements = chars.map((char, charIndex) => (\n                <motion.span\n                    key={\"char-\" + wordIndex + \"-\" + charIndex}\n                    variants={itemVariants}\n                    className=\"inline-block\"\n                >\n                    {char}\n                </motion.span>\n            ));\n\n            elements.push(\n                <span key={wordIndex} className=\"inline-block whitespace-nowrap\">\n                    {charElements}\n                </span>\n            );\n            if (wordIndex < words.length - 1) {\n                elements.push(<span key={\"space-\" + wordIndex} className=\"inline-block\">&nbsp;</span>);\n            }\n        }\n    });\n\n    return (\n        <motion.div\n            ref={ref}\n            variants={containerVariants}\n            initial=\"hidden\"\n            animate={controls}\n            className={cn(\"inline-flex flex-wrap items-center\", className)}\n        >\n            {elements}\n        </motion.div>\n    );\n}\n",
  "circular-text": "\"use client\";\r\n\r\nimport React, { useEffect } from \"react\";\r\nimport { motion, useAnimation } from \"framer-motion\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ninterface CircularTextProps {\r\n    text: string;\r\n    radius?: number;\r\n    className?: string;\r\n    spinDuration?: number;\r\n    onHover?: \"slowDown\" | \"speedUp\" | \"pause\" | \"goBonkers\";\r\n}\r\n\r\nexport function CircularText({\r\n    text,\r\n    radius = 100,\r\n    spinDuration = 10,\r\n    onHover = \"slowDown\",\r\n    className,\r\n}: CircularTextProps) {\r\n    const letters = text.split(\"\");\r\n    const controls = useAnimation();\r\n\r\n    useEffect(() => {\r\n        controls.start({\r\n            rotate: 360,\r\n            transition: {\r\n                ease: \"linear\",\r\n                duration: spinDuration,\r\n                repeat: Infinity,\r\n            },\r\n        });\r\n    }, [controls, spinDuration]);\r\n\r\n    const handleHoverStart = () => {\r\n        if (!onHover) return;\r\n        switch (onHover) {\r\n            case \"slowDown\":\r\n                controls.start({\r\n                    rotate: 360,\r\n                    transition: { ease: \"linear\", duration: spinDuration * 3, repeat: Infinity },\r\n                });\r\n                break;\r\n            case \"speedUp\":\r\n                controls.start({\r\n                    rotate: 360,\r\n                    transition: { ease: \"linear\", duration: spinDuration / 4, repeat: Infinity },\r\n                });\r\n                break;\r\n            case \"pause\":\r\n                controls.stop();\r\n                break;\r\n            case \"goBonkers\":\r\n                controls.start({\r\n                    rotate: 360,\r\n                    transition: { ease: \"backInOut\", duration: 1, repeat: Infinity },\r\n                });\r\n                break;\r\n        }\r\n    };\r\n\r\n    const handleHoverEnd = () => {\r\n        controls.start({\r\n            rotate: 360,\r\n            transition: { ease: \"linear\", duration: spinDuration, repeat: Infinity },\r\n        });\r\n    };\r\n\r\n    return (\r\n        <motion.div\r\n            animate={controls}\r\n            onHoverStart={handleHoverStart}\r\n            onHoverEnd={handleHoverEnd}\r\n            className={cn(\"relative flex items-center justify-center rounded-full font-mono uppercase tracking-widest\", className)}\r\n            style={{ width: radius * 2, height: radius * 2 }}\r\n        >\r\n            {letters.map((letter, i) => {\r\n                const rotation = (360 / letters.length) * i;\r\n                return (\r\n                    <span\r\n                        key={i}\r\n                        className=\"absolute origin-bottom font-bold\"\r\n                        style={{\r\n                            height: radius,\r\n                            transform: `rotate(${rotation}deg)`,\r\n                            transformOrigin: \"bottom center\",\r\n                            top: 0,\r\n                            left: \"50%\",\r\n                            marginLeft: \"-0.5ch\"\r\n                        }}\r\n                    >\r\n                        {letter}\r\n                    </span>\r\n                );\r\n            })}\r\n        </motion.div>\r\n    );\r\n}\r\n",
  "curved-loop": "\"use client\";\n\nimport { useId, useMemo, useRef, useEffect, useState } from \"react\";\nimport { cn } from \"@/lib/utils\";\n\ninterface CurvedLoopProps {\n    children: string;\n    className?: string;\n    speed?: number;\n    amplitude?: number;\n    frequency?: number;\n}\n\nexport function CurvedLoop({\n    children,\n    className,\n    speed = 10,\n    amplitude = 40,\n    frequency = 300,\n}: CurvedLoopProps) {\n    const pathRef = useRef<SVGPathElement>(null);\n    const [segmentLength, setSegmentLength] = useState(0);\n\n    const pathData = useMemo(() => {\n        let d = `M 0 ${amplitude + 10} `;\n        for (let i = 0; i < 30; i++) {\n            const start = i * frequency;\n            const mid = start + frequency / 2;\n            const end = start + frequency;\n            d += `Q ${start + frequency / 4} 10 ${mid} ${amplitude + 10} `;\n            d += `T ${end} ${amplitude + 10} `;\n        }\n        return d;\n    }, [amplitude, frequency]);\n\n    useEffect(() => {\n        if (pathRef.current) {\n            const totalLen = pathRef.current.getTotalLength();\n            setSegmentLength(totalLen / 30);\n        }\n    }, [pathData]);\n\n    const id = `curve-${useId()}`;\n\n    const repeatedText = useMemo(() => {\n        const spacer = \" \\u00A0\\u00A0 \";\n        return Array(20)\n            .fill(children + spacer)\n            .join(\"\");\n    }, [children]);\n\n    return (\n        <div\n            className={cn(\"w-full overflow-hidden relative\", className)}\n            style={{ height: amplitude * 2 + 20 }}\n        >\n            <svg className=\"absolute inset-0 w-[500vw] h-full\">\n                <path\n                    id={id}\n                    ref={pathRef}\n                    d={pathData}\n                    fill=\"none\"\n                    stroke=\"none\"\n                />\n                {segmentLength > 0 && (\n                    <text className=\"fill-current text-2xl tracking-widest font-black uppercase\">\n                        <textPath href={`#${id}`}>\n                            {repeatedText}\n                            <animate\n                                attributeName=\"startOffset\"\n                                from=\"0\"\n                                to={`${-segmentLength}`}\n                                dur={`${speed}s`}\n                                repeatCount=\"indefinite\"\n                            />\n                        </textPath>\n                    </text>\n                )}\n            </svg>\n        </div>\n    );\n}\n",
  "kinetic-text": "\"use client\";\r\n\r\nimport { useEffect, useRef } from \"react\";\r\nimport { motion, useInView, useAnimation, Variants } from \"framer-motion\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ninterface KineticTextProps {\r\n    children: string;\r\n    className?: string;\r\n    delay?: number;\r\n    stagger?: number;\r\n    duration?: number;\r\n    splitBy?: \"chars\" | \"words\"; // Add words option if they want whole words\r\n    once?: boolean;\r\n}\r\n\r\nexport function KineticText({\r\n    children,\r\n    className,\r\n    delay = 0,\r\n    stagger = 0.05,\r\n    duration = 0.8,\r\n    splitBy = \"chars\",\r\n    once = false,\r\n}: KineticTextProps) {\r\n    const ref = useRef<HTMLDivElement>(null);\r\n    const inView = useInView(ref, { once });\r\n    const controls = useAnimation();\r\n\r\n    useEffect(() => {\r\n        if (inView) {\r\n            controls.start(\"visible\");\r\n        } else if (!once) {\r\n            controls.start(\"hidden\");\r\n        }\r\n    }, [inView, controls, once]);\r\n\r\n    const elements = splitBy === \"chars\" ? children.split(\"\") : children.split(\" \");\r\n\r\n    const containerVariants = {\r\n        hidden: { opacity: 0 },\r\n        visible: {\r\n            opacity: 1,\r\n            transition: {\r\n                staggerChildren: stagger,\r\n                delayChildren: delay,\r\n            },\r\n        },\r\n    };\r\n\r\n    const itemVariants: Variants = {\r\n        hidden: {\r\n            opacity: 0,\r\n            y: 40,\r\n            rotateX: -90,\r\n            filter: \"blur(10px)\",\r\n        },\r\n        visible: {\r\n            opacity: 1,\r\n            y: 0,\r\n            rotateX: 0,\r\n            filter: \"blur(0px)\",\r\n            transition: {\r\n                type: \"spring\",\r\n                damping: 12,\r\n                stiffness: 100,\r\n                duration: duration,\r\n            },\r\n        },\r\n    };\r\n\r\n    return (\n        <motion.div\n            ref={ref}\n            variants={containerVariants}\n            initial=\"hidden\"\n            animate={controls}\n            className={cn(\"inline-flex flex-wrap items-center overflow-visible leading-[1.1] [perspective:1000px]\", className)}\n        >\n            {elements.map((element, index) => (\n                <motion.span\n                    key={index}\n                    variants={itemVariants}\n                    style={{ whiteSpace: \"pre\" }} // preserve spaces if splitting by words\n                    className=\"inline-block relative origin-bottom cursor-crosshair will-change-transform\"\n                    whileHover={{\n                        scale: 1.4,\n                        rotateZ: index % 2 === 0 ? 4 : -4,\n                        y: -8,\r\n                        color: \"#fff\",\r\n                        textShadow: \"0px 10px 20px rgba(255,255,255,0.4)\",\r\n                        transition: { type: \"spring\", damping: 12, stiffness: 300 }\r\n                    }}\r\n                >\r\n                    {element === \" \" && splitBy === \"chars\" ? \"\\u00A0\" : element}\r\n                    {splitBy === \"words\" && index < elements.length - 1 ? \"\\u00A0\" : null}\r\n                </motion.span>\r\n            ))}\r\n        </motion.div>\r\n    );\r\n}\r\n",
  "scramble-reveal": "\"use client\";\n\nimport { useEffect, useRef, useState } from \"react\";\nimport { useAnimationFrame, useInView } from \"framer-motion\";\nimport { cn } from \"@/lib/utils\";\n\ninterface ScrambleRevealProps {\n    children: string;\n    className?: string;\n    characters?: string;\n    duration?: number;\n    delay?: number;\n    once?: boolean;\n}\n\nconst DEFAULT_CHARS = \"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()_+\";\n\nexport function ScrambleReveal({\n    children,\n    className,\n    characters = DEFAULT_CHARS,\n    duration = 1,\n    delay = 0,\n    once = true,\n}: ScrambleRevealProps) {\n    const text = children;\n    const safeCharacters = characters.length > 0 ? characters : DEFAULT_CHARS;\n    // Initial state: normal text so SSR doesn't mismatch, scrambled client-side when animating\n    const [displayText, setDisplayText] = useState<string>(text);\n    const ref = useRef<HTMLSpanElement>(null);\n    const inView = useInView(ref, { once });\n\n    const [isAnimating, setIsAnimating] = useState(false);\n    const startTimeRef = useRef<number | null>(null);\n\n    useEffect(() => {\n        if (inView) {\n            startTimeRef.current = null;\n            if (delay > 0) {\n                const scrambledInit = text.split(\"\").map(c => c === \" \" ? \" \" : safeCharacters[Math.floor(Math.random() * safeCharacters.length)]).join(\"\");\n                // eslint-disable-next-line react-hooks/set-state-in-effect\n                setDisplayText(scrambledInit);\n            }\n            const timer = setTimeout(() => {\n                setIsAnimating(true);\n            }, delay * 1000);\n            return () => clearTimeout(timer);\n        } else if (!once) {\n            setIsAnimating(false);\n            setDisplayText(text);\n        }\n    }, [inView, delay, once, text, safeCharacters]);\n\n    useAnimationFrame((time) => {\n        if (!isAnimating) return;\n\n        if (startTimeRef.current === null) {\n            startTimeRef.current = time;\n        }\n\n        const elapsed = time - startTimeRef.current;\n        const progress = Math.min(elapsed / (duration * 1000), 1);\n\n        if (progress === 1) {\n            setDisplayText(text);\n            setIsAnimating(false);\n            return;\n        }\n\n        const charArray = text.split(\"\");\n        const revealCount = Math.floor(progress * charArray.length);\n\n        const scrambled = charArray.map((char, index) => {\n            if (char === \" \") return \" \";\n            if (index < revealCount) {\n                return char;\n            }\n            return safeCharacters[Math.floor(Math.random() * safeCharacters.length)];\n        });\n\n        setDisplayText(scrambled.join(\"\"));\n    });\n\n    return (\n        <span ref={ref} className={cn(\"inline-block whitespace-pre-wrap\", className)}>\n            {displayText}\n        </span>\n    );\n}\n",
  "shuffle": "\"use client\";\r\n\r\nimport { useEffect, useMemo, useRef, useState } from \"react\";\r\nimport { useAnimationFrame } from \"framer-motion\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ninterface ShuffleTextProps {\r\n    texts: string[];\r\n    className?: string;\r\n    characterSet?: string;\r\n    interval?: number;\r\n    shuffleDuration?: number;\r\n}\r\n\r\nconst DEFAULT_CHARS = \"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz!@#$%^&*\";\r\n\r\nexport function ShuffleText({\r\n    texts,\r\n    className,\r\n    characterSet = DEFAULT_CHARS,\r\n    interval = 3000,\r\n    shuffleDuration = 0.8,\r\n}: ShuffleTextProps) {\r\n    const safeTexts = useMemo(() => (texts.length > 0 ? texts : [\"\"]), [texts]);\r\n    const safeCharacterSet = useMemo(\r\n        () => (characterSet.length > 0 ? characterSet : DEFAULT_CHARS),\r\n        [characterSet]\r\n    );\r\n    const [currentIndex, setCurrentIndex] = useState(0);\r\n    const [displayText, setDisplayText] = useState(safeTexts[0]);\r\n    const shouldRotate = safeTexts.length > 1;\r\n    const normalizedCurrentIndex = currentIndex >= safeTexts.length ? 0 : currentIndex;\r\n\r\n    const isShuffling = useRef(false);\r\n    const startTimeRef = useRef<number | null>(null);\r\n\r\n    // Initial delay for the first switch\r\n    useEffect(() => {\r\n        if (!shouldRotate) {\r\n            return;\r\n        }\r\n\r\n        const switchInterval = setInterval(() => {\r\n            setCurrentIndex((prev) => (prev + 1) % safeTexts.length);\r\n            isShuffling.current = true;\r\n            startTimeRef.current = null; // Reset animation time for new word\r\n        }, interval);\r\n\r\n        return () => clearInterval(switchInterval);\r\n    }, [interval, safeTexts.length, shouldRotate]);\r\n\r\n    useAnimationFrame((time) => {\r\n        if (!shouldRotate) {\r\n            if (displayText !== safeTexts[0]) {\r\n                setDisplayText(safeTexts[0]);\r\n            }\r\n            return;\r\n        }\r\n\r\n        if (!isShuffling.current) return;\r\n\r\n        if (startTimeRef.current === null) {\r\n            startTimeRef.current = time;\r\n        }\r\n\r\n        const elapsed = time - startTimeRef.current;\r\n        const progress = Math.min(elapsed / (shuffleDuration * 1000), 1);\r\n\r\n        const targetText = safeTexts[normalizedCurrentIndex] ?? \"\";\r\n\r\n        if (progress === 1) {\r\n            setDisplayText(targetText);\r\n            isShuffling.current = false;\r\n            return;\r\n        }\r\n\r\n        const targetLength = targetText.length;\r\n        const revealCount = Math.floor(progress * targetLength);\r\n\r\n        let scrambledStr = \"\";\r\n        for (let i = 0; i < targetLength; i++) {\r\n            if (targetText[i] === \" \") {\r\n                scrambledStr += \" \";\r\n            } else if (i < revealCount) {\r\n                scrambledStr += targetText[i];\r\n            } else {\r\n                scrambledStr += safeCharacterSet[Math.floor(Math.random() * safeCharacterSet.length)];\r\n            }\r\n        }\r\n\r\n        setDisplayText(scrambledStr);\r\n    });\r\n\r\n    return (\r\n        <span className={cn(\"inline-block whitespace-pre-wrap\", className)}>\r\n            {displayText}\r\n        </span>\r\n    );\r\n}\r\n",
  "split-text": "\"use client\";\r\n\r\nimport { useEffect, useRef } from \"react\";\r\nimport { motion, useInView, useAnimation, Variants } from \"framer-motion\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ntype AnimationStyle = \"slideUp\" | \"slideDown\" | \"fade\" | \"blur\";\r\n\r\ninterface SplitTextProps {\r\n    children: string;\r\n    className?: string;\r\n    delay?: number;\r\n    stagger?: number;\r\n    duration?: number;\r\n    splitBy?: \"chars\" | \"words\";\r\n    animation?: AnimationStyle;\r\n    once?: boolean;\r\n    onComplete?: () => void;\r\n}\r\n\r\nconst getVariants = (animation: AnimationStyle, duration: number): Variants => {\r\n    switch (animation) {\r\n        case \"slideUp\":\r\n            return {\r\n                hidden: { y: \"150%\", opacity: 0 },\r\n                visible: {\r\n                    y: 0,\r\n                    opacity: 1,\r\n                    transition: { type: \"spring\", damping: 18, stiffness: 200, duration },\r\n                },\r\n            };\r\n        case \"slideDown\":\r\n            return {\r\n                hidden: { y: \"-150%\", opacity: 0 },\r\n                visible: {\r\n                    y: 0,\r\n                    opacity: 1,\r\n                    transition: { type: \"spring\", damping: 18, stiffness: 200, duration },\r\n                },\r\n            };\r\n        case \"fade\":\r\n            return {\r\n                hidden: { opacity: 0 },\r\n                visible: {\r\n                    opacity: 1,\r\n                    transition: { duration, ease: \"easeOut\" },\r\n                },\r\n            };\r\n        case \"blur\":\r\n            return {\r\n                hidden: { opacity: 0, filter: \"blur(12px)\", scale: 0.9 },\r\n                visible: {\r\n                    opacity: 1,\r\n                    filter: \"blur(0px)\",\r\n                    scale: 1,\r\n                    transition: { duration: duration * 1.5, ease: \"backOut\" },\r\n                },\r\n            };\r\n        default:\r\n            return {\r\n                hidden: { opacity: 0 },\r\n                visible: { opacity: 1 },\r\n            };\r\n    }\r\n};\r\n\r\nexport function SplitText({\r\n    children,\r\n    className,\r\n    delay = 0,\r\n    stagger = 0.05,\r\n    duration = 0.6,\r\n    splitBy = \"chars\",\r\n    animation = \"slideUp\",\r\n    once = false,\r\n    onComplete,\r\n}: SplitTextProps) {\r\n    const ref = useRef<HTMLDivElement>(null);\r\n    const inView = useInView(ref, { once });\r\n    const controls = useAnimation();\r\n\r\n    useEffect(() => {\r\n        if (inView) {\r\n            controls.start(\"visible\").then(() => {\r\n                if (onComplete) onComplete();\r\n            });\r\n        } else if (!once) {\r\n            controls.start(\"hidden\");\r\n        }\r\n    }, [inView, controls, once, onComplete]);\r\n\r\n    const words = children.split(\" \");\r\n\r\n    // Create elements based on split preference\r\n    const elements: React.ReactNode[] = [];\r\n\r\n    words.forEach((word, wordIndex) => {\r\n        if (splitBy === \"words\") {\r\n            elements.push(\r\n                <span key={wordIndex} className=\"inline-block  overflow-hidden py-2\" style={{ marginTop: \"-0.5rem\", marginBottom: \"-0.5rem\" }}>\r\n                    <motion.span variants={getVariants(animation, duration)} className=\"inline-block\">\r\n                        {word}\r\n                    </motion.span>\r\n                    {wordIndex < words.length - 1 && <span>&nbsp;</span>}\r\n                </span>\r\n            );\r\n        } else {\r\n            // Chars\r\n            const chars = word.split(\"\");\r\n            const charElements = chars.map((char, charIndex) => (\r\n                <span key={`${wordIndex}-${charIndex}`} className=\"inline-block overflow-hidden py-2\" style={{ marginTop: \"-0.5rem\", marginBottom: \"-0.5rem\" }}>\r\n                    <motion.span variants={getVariants(animation, duration)} className=\"inline-block\">\r\n                        {char}\r\n                    </motion.span>\r\n                </span>\r\n            ));\r\n\r\n            elements.push(\r\n                <span key={wordIndex} className=\"inline-block \">\r\n                    {charElements}\r\n                    {wordIndex < words.length - 1 && <span className=\"inline-block\">&nbsp;</span>}\r\n                </span>\r\n            );\r\n        }\r\n    });\r\n\r\n    return (\r\n        <motion.div\r\n            ref={ref}\r\n            initial=\"hidden\"\r\n            animate={controls}\r\n            variants={{\r\n                hidden: { opacity: 0 },\r\n                visible: {\r\n                    opacity: 1,\r\n                    transition: {\r\n                        staggerChildren: stagger,\r\n                        delayChildren: delay,\r\n                    },\r\n                },\r\n            }}\r\n            className={cn(\"inline-flex flex-wrap items-center\", className)}\r\n        >\r\n            {elements}\r\n        </motion.div>\r\n    );\r\n}\r\n",
  "text-pressure": "\"use client\";\n\nimport { useEffect, useMemo, useRef } from \"react\";\nimport { cn } from \"@/lib/utils\";\nimport { usePerformanceMode } from \"@/components/ui/use-performance-mode\";\n\ninterface TextPressureProps {\n    children: string;\n    className?: string;\n    baseWeight?: number;\n    maxWeight?: number;\n    baseScale?: number;\n    maxScale?: number;\n    radius?: number;\n}\n\nexport function TextPressure({\n    children,\n    className,\n    baseWeight = 400,\n    maxWeight = 900,\n    baseScale = 1,\n    maxScale = 1.3,\n    radius = 150,\n}: TextPressureProps) {\n    const containerRef = useRef<HTMLDivElement>(null);\n    const charsRef = useRef<(HTMLSpanElement | null)[]>([]);\n    const charMetricsRef = useRef<{ x: number; y: number }[]>([]);\n    const mouseRef = useRef({ x: -1000, y: -1000 });\n    const rafRef = useRef<number>(0);\n    const isHoveringRef = useRef(false);\n    const { isLowPerformance, prefersReducedMotion } = usePerformanceMode();\n\n    const chars = useMemo(\n        () => children.split(\"\").map((char) => ({ char, isSpace: char === \" \" })),\n        [children]\n    );\n\n    useEffect(() => {\n        const container = containerRef.current;\n        if (!container) return;\n\n        const updateMetrics = () => {\n            charMetricsRef.current = charsRef.current.map((el) => {\n                if (!el) return { x: -1000, y: -1000 };\n\n                const rect = el.getBoundingClientRect();\n                return {\n                    x: rect.left + rect.width / 2,\n                    y: rect.top + rect.height / 2,\n                };\n            });\n        };\n\n        const animate = () => {\n            const mx = mouseRef.current.x;\n            const my = mouseRef.current.y;\n\n            charsRef.current.forEach((el, index) => {\n                if (!el) return;\n                const metric = charMetricsRef.current[index] ?? { x: -1000, y: -1000 };\n                const dist = Math.hypot(mx - metric.x, my - metric.y);\n\n                let weight = baseWeight;\n                let scale = baseScale;\n\n                if (dist < radius) {\n                    const t = 1 - dist / radius;\n                    weight = baseWeight + (maxWeight - baseWeight) * t;\n                    scale = baseScale + (maxScale - baseScale) * t;\n                }\n\n                el.style.fontWeight = String(Math.round(weight));\n                el.style.transform = `scale(${scale.toFixed(3)})`;\n            });\n\n            if (isHoveringRef.current) {\n                rafRef.current = requestAnimationFrame(animate);\n            }\n        };\n\n        const onMouseMove = (e: MouseEvent) => {\n            mouseRef.current.x = e.clientX;\n            mouseRef.current.y = e.clientY;\n        };\n\n        const onMouseEnter = () => {\n            if (isLowPerformance || prefersReducedMotion) return;\n\n            updateMetrics();\n            isHoveringRef.current = true;\n            cancelAnimationFrame(rafRef.current);\n            rafRef.current = requestAnimationFrame(animate);\n        };\n\n        const onMouseLeave = () => {\n            mouseRef.current.x = -1000;\n            mouseRef.current.y = -1000;\n            isHoveringRef.current = false;\n            cancelAnimationFrame(rafRef.current);\n            rafRef.current = requestAnimationFrame(animate);\n        };\n\n        updateMetrics();\n\n        container.addEventListener(\"mousemove\", onMouseMove, { passive: true });\n        container.addEventListener(\"mouseenter\", onMouseEnter);\n        container.addEventListener(\"mouseleave\", onMouseLeave);\n        window.addEventListener(\"resize\", updateMetrics, { passive: true });\n        window.addEventListener(\"scroll\", updateMetrics, { passive: true });\n\n        return () => {\n            container.removeEventListener(\"mousemove\", onMouseMove);\n            container.removeEventListener(\"mouseenter\", onMouseEnter);\n            container.removeEventListener(\"mouseleave\", onMouseLeave);\n            window.removeEventListener(\"resize\", updateMetrics);\n            window.removeEventListener(\"scroll\", updateMetrics);\n            cancelAnimationFrame(rafRef.current);\n        };\n    }, [baseWeight, maxWeight, baseScale, maxScale, radius, isLowPerformance, prefersReducedMotion]);\n\n    return (\n        <div\n            ref={containerRef}\n            className={cn(\n                \"inline-flex flex-wrap items-baseline justify-center cursor-default select-none\",\n                className\n            )}\n        >\n            {chars.map((c, i) =>\n                c.isSpace ? (\n                    <span key={i} className=\"inline-block w-[0.3em]\" />\n                ) : (\n                    <span\n                        key={i}\n                        ref={(el) => { charsRef.current[i] = el; }}\n                        className=\"inline-block transition-[font-weight,transform] duration-150 ease-out\"\n                        style={{\n                            fontWeight: baseWeight,\n                            transformOrigin: \"center bottom\",\n                        }}\n                    >\n                        {c.char}\n                    </span>\n                )\n            )}\n        </div>\n    );\n}\n",
  "text-type": "\"use client\";\r\n\r\nimport React, { useEffect } from \"react\";\r\nimport { motion, useAnimation, useInView } from \"framer-motion\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ninterface TextTypeProps {\r\n    text: string;\r\n    className?: string;\r\n    delay?: number;\r\n    typingSpeed?: number;\r\n    cursorBlinkSpeed?: number;\r\n    showCursor?: boolean;\r\n    cursorChar?: string;\r\n    cursorClassName?: string;\r\n}\r\n\r\nexport function TextType({\r\n    text,\r\n    className,\r\n    delay = 0,\r\n    typingSpeed = 0.05,\r\n    cursorBlinkSpeed = 0.8,\r\n    showCursor = true,\r\n    cursorChar = \"|\",\r\n    cursorClassName,\r\n}: TextTypeProps) {\r\n    const letters = text.split(\"\");\r\n    const controls = useAnimation();\r\n    const ref = React.useRef(null);\r\n    const inView = useInView(ref, { once: true });\r\n\r\n    useEffect(() => {\r\n        if (inView) {\r\n            controls.start(\"visible\");\r\n        }\r\n    }, [inView, controls]);\r\n\r\n    const containerVariants = {\r\n        hidden: { opacity: 1 },\r\n        visible: {\r\n            opacity: 1,\r\n            transition: {\r\n                staggerChildren: typingSpeed,\r\n                delayChildren: delay,\r\n            },\r\n        },\r\n    };\r\n\r\n    const charVariants = {\r\n        hidden: { display: \"none\", opacity: 0 },\r\n        visible: { display: \"inline\", opacity: 1 },\r\n    };\r\n\r\n    return (\r\n        <motion.span\r\n            ref={ref}\r\n            variants={containerVariants}\r\n            initial=\"hidden\"\r\n            animate={controls}\r\n            className={cn(\"inline-block\", className)}\r\n        >\r\n            {letters.map((char, i) => (\r\n                <motion.span key={i} variants={charVariants}>\r\n                    {char === \" \" ? \"\\u00A0\" : char}\r\n                </motion.span>\r\n            ))}\r\n            {showCursor && (\r\n                <motion.span\r\n                    animate={{ opacity: [1, 0] }}\r\n                    transition={{\r\n                        repeat: Infinity,\r\n                        duration: cursorBlinkSpeed,\r\n                        ease: \"linear\",\r\n                    }}\r\n                    className={cn(\"inline-block -ml-1 text-emerald-400\", cursorClassName)}\r\n                >\r\n                    {cursorChar}\r\n                </motion.span>\r\n            )}\r\n        </motion.span>\r\n    );\r\n}\r\n"
} as const;

